import { type HTMLAttributes } from "react";
import { ProductMark } from "./ProductMark";

/**
 * Boreas product mark (a four-point sparkle/star glyph on a rounded-square plate), exported as a
 * raster PNG and embedded as a data URI — same approach as Logo.tsx, no
 * separate asset pipeline needed.
 *
 * MASK_SRC isolates just the glowing glyph from MARK_SRC into its own
 * alpha shape (everything else transparent) — see ProductMark and
 * styles/product-mark.css for what that drives.
 */
const MARK_SRC = "data:image/png;base64,";
const MASK_SRC = "data:image/png;base64,";

export type BoreasMarkProps = HTMLAttributes<HTMLDivElement>;

/**
 * Idle floating animation for the Boreas mark — see ProductMark for the
 * shared chip structure/motion every product mark uses, and
 * styles/product-mark.css for the visual treatment itself.
 *
 * Fixed-size by design (280×280 outer scene, matching the geometry
 * tuned in product-mark.css). Scale the whole thing with a CSS transform
 * on the wrapper if a different size is ever needed.
 */
export function BoreasMark(props: BoreasMarkProps) {
  return <ProductMark markSrc={MARK_SRC} maskSrc={MASK_SRC} alt="Boreas" {...props} />;
}
